class Euler:
    def __init__(self, n_terms):
        self.accuracy = n_terms
        self.terms = [1 / self._factorial(n) for n in range(self.accuracy)]
        self.value = sum(self.terms)
    def _factorial(self, n):
        res = 1
        for i in range(2, n + 1):
            res *= i
        return res
