class EventBus:
    def __init__(self):
        self.handlers = {}
    def on(self, event, fn):
        if event not in self.handlers:
            self.handlers[event] = []
        self.handlers[event].append(fn)
    def emit(self, event, data):
        for fn in self.handlers.get(event, []):
            fn(data)
